css:
body {
  font-family: 'Courier New', 'Consolas', 'Liberation Mono', monospace;
  background-image: url("data:image/svg+xml,%3Csvg width='48' height='48' xmlns='http://www.w3.org/2000/svg'%3E%3Crect width='48' height='48' fill='none'/%3E%3Cpath d='M 48 0 L 0 0 0 48' fill='none' stroke='%231a3560' stroke-width='0.5'/%3E%3C/svg%3E") !important;
}
input, select, textarea, button { font-family: 'Courier New', 'Consolas', 'Liberation Mono', monospace; }
.header { text-transform: uppercase; letter-spacing: 0.12em; border-bottom: 1px solid #3a5a88 !important; }
